// ── Rich SVG preview generator ──────────────────────────────────────────────
function generateSVGPreview(tpl: Template): string {
  const W = 280, H = 280
  const bg = tpl.background_color || "#1a1a2e"
  const layers = tpl.layers || []
  const scaleX = W / (tpl.width || 1080)
  const scaleY = H / (tpl.height || 1080)
  const scale = Math.min(scaleX, scaleY)

  // Parse hex color to lighter/darker for decorative elements
  const c2 = bg === "#FFFFFF" || bg === "#F5F5F0" || bg.toLowerCase() === "#fff"
    ? "#e2e8f0" : lighten(bg, 40)
  const accent = getAccentColor(layers)

  let shapes = ""

  // Background gradient decoration
  shapes += `<defs>
    <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
      <stop offset="0%" style="stop-color:${bg}"/>
      <stop offset="100%" style="stop-color:${darken(bg, 20)}"/>
    </linearGradient>
    <filter id="shadow"><feDropShadow dx="0" dy="2" stdDeviation="3" flood-opacity="0.2"/></filter>
  </defs>`
  shapes += `<rect width="${W}" height="${H}" fill="url(#bg)"/>`

  // Decorative corner accents
  shapes += `<circle cx="0" cy="0" r="60" fill="${accent}" opacity="0.12"/>`
  shapes += `<circle cx="${W}" cy="${H}" r="80" fill="${accent}" opacity="0.08"/>`

  // Render each layer scaled to preview size
  let textCount = 0
  let imageCount = 0

  for (const layer of layers) {
    const x = (layer.x || 0) * scale
    const y = (layer.y || 0) * scale
    const w = (layer.width || 300) * scale
    const h = (layer.height || 300) * scale
    const fs = Math.max(7, Math.min(22, ((layer.font_size || 48) * scale)))

    if (layer.type === "image") {
      imageCount++
      // Render image placeholder as a styled rectangle
      const imgBg = imageCount === 1 ? accent : lighten(accent, 25)
      shapes += `<rect x="${x}" y="${y}" width="${w}" height="${h}"
        rx="4" fill="${imgBg}" opacity="0.35" filter="url(#shadow)"/>`
      shapes += `<rect x="${x+2}" y="${y+2}" width="${w-4}" height="${h-4}"
        rx="3" fill="none" stroke="${accent}" stroke-width="1.5" stroke-dasharray="4,3" opacity="0.6"/>`
      // Image icon in center
      const cx = x + w/2, cy = y + h/2
      const ic = Math.min(w, h) * 0.22
      shapes += `<rect x="${cx-ic}" y="${cy-ic*0.75}" width="${ic*2}" height="${ic*1.5}"
        rx="2" fill="${accent}" opacity="0.5"/>`
      shapes += `<circle cx="${cx-ic*0.3}" cy="${cy-ic*0.15}" r="${ic*0.28}" fill="${bg}" opacity="0.8"/>`
      shapes += `<polygon points="${cx-ic},${cy+ic*0.75} ${cx+ic},${cy+ic*0.75} ${cx+ic*0.3},${cy+ic*0.15}"
        fill="${bg}" opacity="0.6"/>`
    } else if (layer.type === "text" && layer.text) {
      textCount++
      const color = layer.color || (bg === "#FFFFFF" || bg === "#F5F5F0" ? "#1a1a2e" : "#FFFFFF")
      // Clip long text
      const preview = layer.text.substring(0, 20) + (layer.text.length > 20 ? "…" : "")
      shapes += `<text x="${x}" y="${y + fs}" font-family="Arial,sans-serif"
        font-size="${fs}" font-weight="${textCount === 1 ? 'bold' : 'normal'}"
        fill="${color}" opacity="${textCount === 1 ? 1 : 0.85}"
        style="text-overflow:ellipsis;">${escSVG(preview)}</text>`

      // Underline for headlines
      if (textCount === 1 && fs > 12) {
        const tw = Math.min(w || 200, preview.length * fs * 0.55)
        shapes += `<rect x="${x}" y="${y+fs+1}" width="${tw}" height="2" fill="${accent}" opacity="0.7" rx="1"/>`
      }
    }
  }

  // If no layers, show placeholder wireframe
  if (layers.length === 0) {
    const isBright = isBrightColor(bg)
    const ph = isBright ? "#94a3b8" : "rgba(255,255,255,0.3)"
    shapes += `<rect x="30" y="40" width="220" height="130" rx="6" fill="${ph}" opacity="0.3"/>`
    shapes += `<rect x="30" y="185" width="180" height="16" rx="3" fill="${ph}" opacity="0.5"/>`
    shapes += `<rect x="30" y="208" width="130" height="12" rx="3" fill="${ph}" opacity="0.35"/>`
    shapes += `<rect x="30" y="235" width="80" height="28" rx="5" fill="${accent}" opacity="0.6"/>`
  }

  // Size badge
  const sizeLabel = `${tpl.width}×${tpl.height}`
  const slw = sizeLabel.length * 6 + 12
  shapes += `<rect x="${W-slw-4}" y="${H-22}" width="${slw}" height="18" rx="9" fill="rgba(0,0,0,0.4)"/>`
  shapes += `<text x="${W-slw/2-4}" y="${H-10}" font-family="monospace" font-size="9"
    fill="rgba(255,255,255,0.85)" text-anchor="middle">${sizeLabel}</text>`

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}">${shapes}</svg>`
}

// ── SVG color helpers ────────────────────────────────────────────────────────
function lighten(hex: string, pct: number): string {
  try {
    const r = parseInt(hex.slice(1,3)||"44",16), g = parseInt(hex.slice(3,5)||"44",16), b = parseInt(hex.slice(5,7)||"44",16)
    const f = pct/100, nr = Math.min(255,r+Math.round((255-r)*f)), ng = Math.min(255,g+Math.round((255-g)*f)), nb = Math.min(255,b+Math.round((255-b)*f))
    return `#${nr.toString(16).padStart(2,"0")}${ng.toString(16).padStart(2,"0")}${nb.toString(16).padStart(2,"0")}`
  } catch { return "#888888" }
}
function darken(hex: string, pct: number): string {
  try {
    const r = parseInt(hex.slice(1,3)||"44",16), g = parseInt(hex.slice(3,5)||"44",16), b = parseInt(hex.slice(5,7)||"44",16)
    const f = 1-pct/100, nr = Math.max(0,Math.round(r*f)), ng = Math.max(0,Math.round(g*f)), nb = Math.max(0,Math.round(b*f))
    return `#${nr.toString(16).padStart(2,"0")}${ng.toString(16).padStart(2,"0")}${nb.toString(16).padStart(2,"0")}`
  } catch { return "#222222" }
}
function isBrightColor(hex: string): boolean {
  try { const r=parseInt(hex.slice(1,3),16), g=parseInt(hex.slice(3,5),16), b=parseInt(hex.slice(5,7),16); return (r*299+g*587+b*114)/1000 > 140 } catch { return false }
}
function getAccentColor(layers: any[]): string {
  for (const l of layers) { if (l.color && l.color !== "#FFFFFF" && l.color !== "#000000" && l.color.length === 7) return l.color }
  return "#e94560"
}
function escSVG(s: string): string {
  return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;")
}

// ── Main page ────────────────────────────────────────────────────────────────
export default function TemplatesPage() {
  const router = useRouter()
  const { toast } = useToast()

  const [templates, setTemplates] = useState<Template[]>([])
  const [projects, setProjects] = useState<Project[]>([])
  const [loading, setLoading] = useState(true)
  const [activeCategory, setActiveCategory] = useState("all")
  const [searchQuery, setSearchQuery] = useState("")
  const [selectedTemplate, setSelectedTemplate] = useState<Template | null>(null)
  const [showApplyDialog, setShowApplyDialog] = useState(false)
  const [showDetailsDialog, setShowDetailsDialog] = useState(false)
  const [applyTarget, setApplyTarget] = useState<"new"|"existing">("new")
  const [selectedProjectId, setSelectedProjectId] = useState("")
  const [applying, setApplying] = useState(false)
  const [newProjectName, setNewProjectName] = useState("")

  // Add own template state
  const [customName, setCustomName] = useState("")
  const [customCategory, setCustomCategory] = useState("social")
  const [customWidth, setCustomWidth] = useState("1080")
  const [customHeight, setCustomHeight] = useState("1080")
  const [customBg, setCustomBg] = useState("#FFFFFF")
  const [customTags, setCustomTags] = useState("")
  const [customDesc, setCustomDesc] = useState("")
  const [savingCustom, setSavingCustom] = useState(false)

  useEffect(() => { loadTemplates(); loadProjects() }, [])

  const api = async (url: string, opts: RequestInit = {}) => {
    const res = await fetch(`${API_BASE}${url}`, opts)
    if (!res.ok) { const e = await res.json().catch(()=>({})); throw new Error(e.detail || `HTTP ${res.status}`) }
    return res.json()
  }

  const loadTemplates = async () => {
    setLoading(true)
    try {
      const data = await api("/templates/list")
      setTemplates(data.templates || [])
    } catch (e: any) {
      toast({ title: "Could not load templates", description: e.message, variant: "destructive" })
    } finally { setLoading(false) }
  }

  const loadProjects = async () => {
    try {
      const data = await api("/editor/projects")
      setProjects(data.projects || [])
    } catch {}
  }

  const filteredTemplates = templates.filter(t => {
    const matchesCat = activeCategory === "all" || t.category === activeCategory
    const q = searchQuery.toLowerCase()
    const matchesSearch = !q || t.template_name.toLowerCase().includes(q)
      || t.tags?.some(tag => tag.toLowerCase().includes(q))
      || t.category?.toLowerCase().includes(q)
    return matchesCat && matchesSearch
  })

  const openApplyDialog = (tpl: Template) => {
    setSelectedTemplate(tpl)
    setNewProjectName(`${tpl.template_name} — Copy`)
    setShowApplyDialog(true)
  }

  const openDetailsDialog = (tpl: Template, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedTemplate(tpl)
    setShowDetailsDialog(true)
  }

  const applyTemplate = async () => {
    if (!selectedTemplate) return
    setApplying(true)
    try {
      let projectId: string

      if (applyTarget === "new") {
        // Create project first
        const tpl_data = await api(`/templates/${selectedTemplate.template_id}`)
        const tpl = tpl_data.template
        const params = new URLSearchParams({
          width: String(tpl.width || 1080),
          height: String(tpl.height || 1080),
          background_color: tpl.background_color || "#FFFFFF",
          name: newProjectName || tpl.template_name,
        })
        const created = await api(`/editor/create-project?${params}`, { method: "POST" })
        projectId = created.project_id
      } else {
        if (!selectedProjectId) {
          toast({ title: "Select a project first", variant: "destructive" })
          setApplying(false); return
        }
        projectId = selectedProjectId
      }

      // Apply template layers
      await api(`/editor/${projectId}/apply-template/${selectedTemplate.template_id}`, { method: "POST" })
      toast({ title: "Template Applied!", description: "Opening editor…" })
      setShowApplyDialog(false)
      router.push(`/editor?project=${projectId}`)
    } catch (e: any) {
      toast({ title: "Apply failed", description: e.message, variant: "destructive" })
    } finally { setApplying(false) }
  }

  const saveCustomTemplate = async () => {
    if (!customName.trim()) { toast({ title: "Enter a template name", variant: "destructive" }); return }
    setSavingCustom(true)
    try {
      const body = {
        template_name: customName.trim(),
        category: customCategory,
        width: parseInt(customWidth) || 1080,
        height: parseInt(customHeight) || 1080,
        background_color: customBg,
        tags: customTags.split(",").map(t=>t.trim()).filter(Boolean),
        description: customDesc,
        layers: []
      }
      await api("/templates/create", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify(body) })
      toast({ title: "Template Saved!", description: "It now appears in the gallery" })
      setCustomName(""); setCustomTags(""); setCustomDesc("")
      await loadTemplates()
    } catch (e: any) {
      toast({ title: "Save failed", description: e.message, variant: "destructive" })
    } finally { setSavingCustom(false) }
  }

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="border-b border-border bg-card px-8 py-5">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Template Library</h1>
            <p className="text-sm text-muted-foreground mt-0.5">
              {templates.length} professional designs across {Object.keys(CATEGORY_LABELS).length - 1} categories — click to apply instantly
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={loadTemplates} disabled={loading} className="gap-2">
              <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} /> Reseed
            </Button>
          </div>
        </div>

        {/* Search */}
        <div className="relative mt-4 max-w-lg">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Search templates or tags…" className="pl-9"
            value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
        </div>
      </div>

      {/* Tabs: Browse / Add Your Own */}
      <Tabs defaultValue="browse" className="flex-1 flex flex-col min-h-0">
        <div className="px-8 pt-3 border-b border-border bg-card shrink-0">
          <TabsList className="h-9">
            <TabsTrigger value="browse" className="gap-2 text-sm">
              <LayoutTemplate className="h-4 w-4" /> Browse Templates
            </TabsTrigger>
            <TabsTrigger value="custom" className="gap-2 text-sm">
              <Plus className="h-4 w-4" /> Add Your Own
            </TabsTrigger>
          </TabsList>
        </div>

        {/* ── BROWSE TAB ── */}
        <TabsContent value="browse" className="flex-1 min-h-0 mt-0">
          <div className="flex h-full">
            {/* Category sidebar */}
            <div className="w-44 shrink-0 border-r border-border bg-card/50 p-3 space-y-1">
              {CATEGORIES.map(cat => (
                <button
                  key={cat}
                  className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                    activeCategory === cat
                      ? "bg-primary text-primary-foreground font-medium"
                      : "text-muted-foreground hover:bg-muted/50 hover:text-foreground"
                  }`}
                  onClick={() => setActiveCategory(cat)}
                >
                  {CATEGORY_LABELS[cat]}
                </button>
              ))}
            </div>

            {/* Template grid */}
            <ScrollArea className="flex-1">
              <div className="p-6">
                {loading ? (
                  <div className="flex items-center justify-center h-64">
                    <RefreshCw className="h-8 w-8 animate-spin text-primary" />
                  </div>
                ) : filteredTemplates.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-64 text-muted-foreground">
                    <LayoutTemplate className="h-16 w-16 opacity-20 mb-4" />
                    <p className="text-lg font-medium">No templates found</p>
                    <p className="text-sm mt-1">Try a different category or search term</p>
                    <Button variant="outline" className="mt-4" onClick={loadTemplates}>
                      <RefreshCw className="h-4 w-4 mr-2" /> Reseed Templates
                    </Button>
                  </div>
                ) : (
                  <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                    {filteredTemplates.map(tpl => {
                      const svgData = generateSVGPreview(tpl)
                      const svgUrl = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgData)}`
                      const isBright = isBrightColor(tpl.background_color || "#1a1a2e")

                      return (
                        <Card key={tpl.template_id}
                          className="group overflow-hidden border-border hover:border-primary/50 transition-all duration-200 hover:shadow-lg hover:shadow-primary/10 cursor-pointer"
                          onClick={() => openApplyDialog(tpl)}
                        >
                          {/* SVG Preview */}
                          <div className="relative aspect-square overflow-hidden">
                            <img
                              src={svgUrl}
                              alt={tpl.template_name}
                              className="w-full h-full object-cover"
                              draggable={false}
                            />
                            {/* Hover overlay */}
                            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                              <Button size="sm" className="gradient-primary h-8 gap-1.5" onClick={() => openApplyDialog(tpl)}>
                                <CheckCircle className="h-3.5 w-3.5" /> Use Template
                              </Button>
                              <Button size="sm" variant="secondary" className="h-8 gap-1.5"
                                onClick={e => openDetailsDialog(tpl, e)}>
                                <Info className="h-3.5 w-3.5" /> Details
                              </Button>
                            </div>
                            {/* Category badge */}
                            <div className="absolute top-2 left-2">
                              <Badge className="text-[10px] px-1.5 py-0.5 bg-black/50 text-white border-0 backdrop-blur-sm">
                                {CATEGORY_LABELS[tpl.category] || tpl.category}
                              </Badge>
                            </div>
                          </div>

                          <CardContent className="p-3 space-y-2">
                            <div>
                              <p className="font-semibold text-sm leading-tight truncate">{tpl.template_name}</p>
                              <p className="text-xs text-muted-foreground">{tpl.width}×{tpl.height}px</p>
                            </div>
                            <div className="flex flex-wrap gap-1">
                              {(tpl.tags || []).slice(0, 3).map(tag => (
                                <Badge key={tag} variant="secondary" className="text-[10px] px-1.5 py-0">{tag}</Badge>
                              ))}
                              {tpl.layers_count > 0 && (
                                <Badge variant="outline" className="text-[10px] px-1.5 py-0 ml-auto">
                                  {tpl.layers_count} layers
                                </Badge>
                              )}
                            </div>
                            <Button className="w-full h-8 text-xs gradient-primary"
                              onClick={e => { e.stopPropagation(); openApplyDialog(tpl) }}>
                              Use Template →
                            </Button>
                          </CardContent>
                        </Card>
                      )
                    })}
                  </div>
                )}
              </div>
            </ScrollArea>
          </div>
        </TabsContent>

        {/* ── ADD YOUR OWN TAB ── */}
        <TabsContent value="custom" className="flex-1 min-h-0 mt-0 overflow-auto">
          <div className="max-w-2xl mx-auto p-8 space-y-6">
            <div>
              <h2 className="text-xl font-bold">Create Your Own Template</h2>
              <p className="text-sm text-muted-foreground mt-1">
                Save a blank canvas with your preferred dimensions and colors as a reusable template.
                You can then open it in the editor and add layers.
              </p>
            </div>

            <div className="grid gap-5 sm:grid-cols-2">
              <div className="space-y-1.5 sm:col-span-2">
                <Label>Template Name <span className="text-destructive">*</span></Label>
                <Input placeholder="e.g., Summer Sale — Portrait Story"
                  value={customName} onChange={e => setCustomName(e.target.value)} />
              </div>

              <div className="space-y-1.5">
                <Label>Category</Label>
                <Select value={customCategory} onValueChange={setCustomCategory}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {CATEGORIES.filter(c=>c!=="all").map(c =>
                      <SelectItem key={c} value={c}>{CATEGORY_LABELS[c]}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-1.5">
                <Label>Background Color</Label>
                <div className="flex gap-2">
                  <input type="color" value={customBg} onChange={e=>setCustomBg(e.target.value)}
                    className="w-12 h-10 rounded border cursor-pointer shrink-0" />
                  <Input value={customBg} onChange={e=>setCustomBg(e.target.value)} className="font-mono" />
                </div>
              </div>

              <div className="space-y-1.5">
                <Label>Width (px)</Label>
                <Input type="number" value={customWidth} onChange={e=>setCustomWidth(e.target.value)} min="100" max="5000" />
              </div>

              <div className="space-y-1.5">
                <Label>Height (px)</Label>
                <Input type="number" value={customHeight} onChange={e=>setCustomHeight(e.target.value)} min="100" max="5000" />
              </div>

              <div className="space-y-1.5 sm:col-span-2">
                <Label>Tags (comma-separated)</Label>
                <Input placeholder="instagram, portrait, fashion…"
                  value={customTags} onChange={e=>setCustomTags(e.target.value)} />
              </div>

              <div className="space-y-1.5 sm:col-span-2">
                <Label>Description (optional)</Label>
                <Textarea placeholder="Describe the intended use of this template…" rows={3}
                  value={customDesc} onChange={e=>setCustomDesc(e.target.value)} />
              </div>
            </div>

            {/* Canvas preview */}
            {(parseInt(customWidth) > 0 && parseInt(customHeight) > 0) && (
              <div className="p-4 border border-border rounded-lg bg-muted/30">
                <p className="text-xs text-muted-foreground mb-3 font-medium uppercase tracking-wider">Preview</p>
                <div className="flex items-center gap-4">
                  <div className="rounded shadow-md border border-border/50"
                    style={{
                      background: customBg,
                      width: Math.min(120, 120 * parseInt(customWidth) / Math.max(parseInt(customWidth), parseInt(customHeight))),
                      height: Math.min(120, 120 * parseInt(customHeight) / Math.max(parseInt(customWidth), parseInt(customHeight))),
                    }} />
                  <div className="space-y-1">
                    <p className="font-medium">{customName || "Untitled Template"}</p>
                    <p className="text-sm text-muted-foreground">{customWidth}×{customHeight}px</p>
                    <p className="text-sm text-muted-foreground capitalize">{CATEGORY_LABELS[customCategory]}</p>
                    {customTags && (
                      <div className="flex flex-wrap gap-1 pt-1">
                        {customTags.split(",").slice(0,4).map(t=>t.trim()).filter(Boolean).map(t=>
                          <Badge key={t} variant="secondary" className="text-xs">{t}</Badge>)}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}

            <Button className="gradient-primary gap-2" onClick={saveCustomTemplate}
              disabled={savingCustom || !customName.trim()}>
              {savingCustom
                ? <><RefreshCw className="h-4 w-4 animate-spin" /> Saving…</>
                : <><Upload className="h-4 w-4" /> Save Template</>}
            </Button>
          </div>
        </TabsContent>
      </Tabs>

      {/* ── Apply Dialog ───────────────────────────────────────────────── */}
      <Dialog open={showApplyDialog} onOpenChange={setShowApplyDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <CheckCircle className="h-5 w-5 text-primary" /> Apply Template
            </DialogTitle>
            <DialogDescription>
              Apply <strong>{selectedTemplate?.template_name}</strong> ({selectedTemplate?.width}×{selectedTemplate?.height}px)
            </DialogDescription>
          </DialogHeader>

          {selectedTemplate && (
            <div className="py-1">
              {/* Template mini-preview */}
              <div className="rounded-lg overflow-hidden border border-border mb-4">
                <img
                  src={`data:image/svg+xml;charset=utf-8,${encodeURIComponent(generateSVGPreview(selectedTemplate))}`}
                  alt={selectedTemplate.template_name}
                  className="w-full h-36 object-cover"
                />
              </div>

              <div className="space-y-4">
                {/* Target choice */}
                <div className="grid grid-cols-2 gap-3">
                  <button
                    onClick={() => setApplyTarget("new")}
                    className={`p-3 rounded-lg border-2 text-left transition-colors ${applyTarget === "new" ? "border-primary bg-primary/5" : "border-border hover:border-primary/40"}`}
                  >
                    <Plus className="h-5 w-5 mb-1.5 text-primary" />
                    <p className="font-medium text-sm">New Project</p>
                    <p className="text-xs text-muted-foreground">Start fresh with this template</p>
                  </button>
                  <button
                    onClick={() => setApplyTarget("existing")}
                    className={`p-3 rounded-lg border-2 text-left transition-colors ${applyTarget === "existing" ? "border-primary bg-primary/5" : "border-border hover:border-primary/40"}`}
                  >
                    <FolderOpen className="h-5 w-5 mb-1.5 text-primary" />
                    <p className="font-medium text-sm">Existing Project</p>
                    <p className="text-xs text-muted-foreground">Apply to one I already have</p>
                  </button>
                </div>

                {applyTarget === "new" && (
                  <div className="space-y-1.5">
                    <Label className="text-sm">Project Name</Label>
                    <Input value={newProjectName} onChange={e => setNewProjectName(e.target.value)}
                      placeholder="Enter project name…" />
                  </div>
                )}

                {applyTarget === "existing" && (
                  <div className="space-y-1.5">
                    <Label className="text-sm">Select Project</Label>
                    {projects.length === 0 ? (
                      <p className="text-sm text-muted-foreground border border-dashed border-border rounded p-3 text-center">
                        No projects yet — create a new project first
                      </p>
                    ) : (
                      <Select value={selectedProjectId} onValueChange={setSelectedProjectId}>
                        <SelectTrigger>
                          <SelectValue placeholder="Choose a project…" />
                        </SelectTrigger>
                        <SelectContent>
                          {projects.map(p => (
                            <SelectItem key={p.id} value={p.id}>
                              {p.name} ({p.width}×{p.height})
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    )}
                    {selectedProjectId && (
                      <p className="text-xs text-amber-500">⚠️ This will add template layers on top of existing layers</p>
                    )}
                  </div>
                )}
              </div>
            </div>
          )}

          <DialogFooter className="gap-2">
            <Button variant="outline" onClick={() => setShowApplyDialog(false)}>Cancel</Button>
            <Button className="gradient-primary gap-2" onClick={applyTemplate}
              disabled={applying || (applyTarget === "existing" && !selectedProjectId)}>
              {applying ? <><RefreshCw className="h-4 w-4 animate-spin" /> Applying…</> : "Apply & Open Editor →"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Details Dialog ─────────────────────────────────────────────── */}
      <Dialog open={showDetailsDialog} onOpenChange={setShowDetailsDialog}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedTemplate?.template_name}</DialogTitle>
            <DialogDescription>Template details and specifications</DialogDescription>
          </DialogHeader>
          {selectedTemplate && (
            <div className="space-y-4">
              <div className="rounded-lg overflow-hidden border border-border">
                <img
                  src={`data:image/svg+xml;charset=utf-8,${encodeURIComponent(generateSVGPreview(selectedTemplate))}`}
                  alt={selectedTemplate.template_name}
                  className="w-full h-48 object-cover"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-0.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider">Dimensions</p>
                  <p className="font-medium">{selectedTemplate.width} × {selectedTemplate.height} px</p>
                </div>
                <div className="space-y-0.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider">Category</p>
                  <p className="font-medium capitalize">{CATEGORY_LABELS[selectedTemplate.category] || selectedTemplate.category}</p>
                </div>
                <div className="space-y-0.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider">Layers</p>
                  <p className="font-medium">{selectedTemplate.layers_count || (selectedTemplate.layers?.length ?? 0)} layers</p>
                </div>
                <div className="space-y-0.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider">Background</p>
                  <div className="flex items-center gap-2">
                    <div className="w-5 h-5 rounded border border-border" style={{ background: selectedTemplate.background_color || "#fff" }} />
                    <p className="font-mono text-sm">{selectedTemplate.background_color || "#FFFFFF"}</p>
                  </div>
                </div>
              </div>
              {selectedTemplate.tags?.length > 0 && (
                <div className="space-y-1.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider flex items-center gap-1">
                    <Tag className="h-3 w-3" /> Tags
                  </p>
                  <div className="flex flex-wrap gap-1.5">
                    {selectedTemplate.tags.map(tag => (
                      <Badge key={tag} variant="secondary">{tag}</Badge>
                    ))}
                  </div>
                </div>
              )}
              {selectedTemplate.description && (
                <div className="space-y-1.5">
                  <p className="text-xs text-muted-foreground uppercase tracking-wider">Description</p>
                  <p className="text-sm">{selectedTemplate.description}</p>
                </div>
              )}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDetailsDialog(false)}>Close</Button>
            <Button className="gradient-primary" onClick={() => { setShowDetailsDialog(false); setShowApplyDialog(true) }}>
              Use This Template →
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}